// // This comment suggests the counter decrements on each positive clock edge and wraps around from 15 to 0.
module top_module(
input clk,reset,
output reg [3:0] counter
    );always @(posedge clk)   
begin  
    if(reset)
        counter <= 4'b0000;
    else if(counter != 4'b1111)
        counter <= counter + 1;
    else
        counter <= 4'b0000;        
end    
endmodule
